function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'daily');
const expectedFreshnessHours = 36;
const isFresh = (new Date() - new Date(now)) / 3600000 < expectedFreshnessHours;

const lookbackDays = 180;
const end = new Date();
const start = new Date(end);
start.setDate(start.getDate() - lookbackDays);
const seriesKey = 'EXR.D.BRL.EUR.SP00.A';

function formatIsoDate(date) {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

function parseCsvLine(line) {
  const values = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];

    if (char === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (char === ',' && !inQuotes) {
      values.push(current);
      current = '';
    } else {
      current += char;
    }
  }

  values.push(current);
  return values;
}

function toNumber(value, decimals = 6) {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  if (Number.isNaN(numeric)) return null;
  return Number(numeric.toFixed(decimals));
}

const lines = raw.split(/\r?\n/).filter((line) => line.trim() !== '');
if (!lines.length) {
  throw new Error('ECB Data Portal response is empty');
}

const headers = parseCsvLine(lines[0]).map((header) => header.trim());
const timeIndex = headers.findIndex((header) => header === 'TIME_PERIOD');
const valueIndex = headers.findIndex((header) => header === 'OBS_VALUE');

if (timeIndex === -1 || valueIndex === -1) {
  throw new Error('Unexpected ECB CSV schema: TIME_PERIOD or OBS_VALUE missing');
}

const rows = lines.slice(1)
  .map((line) => {
    const values = parseCsvLine(line);
    const timePeriod = (values[timeIndex] ?? '').trim();
    const obsValue = toNumber((values[valueIndex] ?? '').trim(), 6);

    return {
      quote_date: timePeriod,
      fx_rate_brl_per_eur: obsValue
    };
  })
  .filter((row) => row.quote_date && row.fx_rate_brl_per_eur !== null)
  .sort((a, b) => a.quote_date.localeCompare(b.quote_date));

if (!rows.length) {
  throw new Error('ECB Data Portal returned no valid FX observations in the selected period');
}

const latest = rows[rows.length - 1];
const previous = rows.length > 1 ? rows[rows.length - 2] : null;
const recentSeries = rows.slice(-10);
const fxValues = rows.map((row) => row.fx_rate_brl_per_eur).filter((value) => typeof value === 'number');
const minFx = fxValues.length ? Number(Math.min(...fxValues).toFixed(6)) : null;
const maxFx = fxValues.length ? Number(Math.max(...fxValues).toFixed(6)) : null;
const avgFx = fxValues.length ? Number((fxValues.reduce((sum, value) => sum + value, 0) / fxValues.length).toFixed(6)) : null;
const rangeFx = minFx !== null && maxFx !== null ? Number((maxFx - minFx).toFixed(6)) : null;

const changeVsPrevious = previous ? Number((latest.fx_rate_brl_per_eur - previous.fx_rate_brl_per_eur).toFixed(6)) : null;
const changePctVsPrevious = previous && previous.fx_rate_brl_per_eur ? Number((((latest.fx_rate_brl_per_eur - previous.fx_rate_brl_per_eur) / previous.fx_rate_brl_per_eur) * 100).toFixed(6)) : null;

let movementLabel = 'stable';
let summaryEn = `Latest ECB EUR/BRL reference rate on ${latest.quote_date} was ${latest.fx_rate_brl_per_eur.toFixed(6)} BRL per EUR.`;
const signals = [
  `Latest ECB EUR/BRL ${latest.fx_rate_brl_per_eur.toFixed(6)}`,
  `${lookbackDays}-day EUR/BRL range ${rangeFx !== null ? rangeFx.toFixed(6) : 'n/a'}`,
  `Series key ${seriesKey}`
];

if (changeVsPrevious !== null) {
  if (changeVsPrevious > 0) movementLabel = 'brl_weaker_vs_eur';
  else if (changeVsPrevious < 0) movementLabel = 'brl_stronger_vs_eur';

  summaryEn += ` Versus the previous observation, the rate changed by ${changeVsPrevious.toFixed(6)} (${changePctVsPrevious.toFixed(6)}%).`;
  if (movementLabel === 'brl_weaker_vs_eur') {
    summaryEn += ' This indicates BRL weakening against EUR versus the previous ECB reference rate.';
    signals.push('BRL weakened versus EUR compared with previous ECB fixing');
  } else if (movementLabel === 'brl_stronger_vs_eur') {
    summaryEn += ' This indicates BRL strengthening against EUR versus the previous ECB reference rate.';
    signals.push('BRL strengthened versus EUR compared with previous ECB fixing');
  } else {
    signals.push('ECB EUR/BRL unchanged versus previous fixing');
  }
}

return [{
  json: {
    source: 'ECB_DATA_PORTAL',
    source_format: 'sdmx_csvdata',
    source_url_template: 'https://data-api.ecb.europa.eu/service/data/EXR/D.BRL.EUR.SP00.A?...',
    source_url: 'https://data-api.ecb.europa.eu/service/data/EXR/D.BRL.EUR.SP00.A?...',
    country: 'BR',
    macroarea: 'prices',
    collected_at: now,
    collected_period: _collectedPeriod,
        is_fresh: isFresh,
    dataset: 'EXR',
    series_key: seriesKey,
    base_currency: 'EUR',
    quote_currency: 'BRL',
    lookback_days: lookbackDays,
    query_start_date: formatIsoDate(start),
    query_end_date: formatIsoDate(end),
    total_quotes: rows.length,
    quote_date: latest.quote_date,
    fx_rate_brl_per_eur: latest.fx_rate_brl_per_eur,
    movement_label: movementLabel,
    previous_quote_date: previous ? previous.quote_date : null,
    previous_fx_rate_brl_per_eur: previous ? previous.fx_rate_brl_per_eur : null,
    change_vs_previous: changeVsPrevious,
    change_pct_vs_previous: changePctVsPrevious,
    fx_stats_lookback: {
      min: minFx,
      avg: avgFx,
      max: maxFx,
      range: rangeFx
    },
    recent_series: recentSeries,
    summary_en: summaryEn,
    signals,
    _chart_fields: ["recent_series"]
  }
}];

const now = new Date().toISOString();
const meta = $('ECB Parse Signals').item.json;

return [{
  json: {
    source: 'ECB_DATA_PORTAL',
    country: 'BR',
    macroarea: 'prices',
    cadenza: 'daily',
    run_date: now,
    status: 'done',
    completed_at: now,
    quote_date: meta.quote_date || null,
  },
}];

const raw = ($json.text || '').trim();
const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim();
const parsed = JSON.parse(cleaned);
const base = $('ECB Data Portal Parse').item.json;

return [{ json: {
  ...base,
  rule_based_signals: Array.isArray(base.signals) ? base.signals : [],
  rule_based_movement_label: base.movement_label || 'mixed',
  fallback_summary_en: base.summary_en || '',
  movement_label: parsed.movement_label || base.movement_label || 'mixed',
  signals: Array.isArray(parsed.signals) && parsed.signals.length ? parsed.signals : (Array.isArray(base.signals) ? base.signals : []),
  summary_en: parsed.summary_en || base.summary_en || ''
}}];

const item = $input.first();
const err = item.json?.error ?? item.error?.message ?? '';
const statusCode = item.json?.statusCode ?? item.json?.status ?? 0;
if (err || statusCode >= 400) {
  return [{ json: {
    _api_skip: true,
    source: '08_ECB_FX',
    country: 'BR',
    status: 'skipped_api_error',
    reason: `API unavailable: ${err || 'HTTP ' + statusCode}`,
    run_date: new Date().toISOString(),
    completed_at: new Date().toISOString()
  } }];
}
return [{ json: item.json }];
